#!/usr/bin/env python3
"""Minimum Viable Signal Consumer — polls and validates signals."""
import json, hashlib, os, time, urllib.request
from datetime import datetime, timezone

PRODUCER_ENDPOINT = os.environ.get("PF_PRODUCER_ENDPOINT", "http://localhost:8080")
POLL_INTERVAL = int(os.environ.get("PF_POLL_INTERVAL", "900"))
OUTPUT_DIR = os.environ.get("PF_OUTPUT_DIR", "./signals")

REQUIRED_FIELDS = ["signal_id", "symbol", "direction", "confidence", "timestamp"]

def fetch_signals():
    """Fetch latest signals from producer."""
    url = f"{PRODUCER_ENDPOINT}/signals"
    req = urllib.request.Request(url, headers={"Accept": "application/json"})
    with urllib.request.urlopen(req, timeout=30) as resp:
        return json.loads(resp.read())

def validate_signal(sig):
    """Basic structural validation."""
    for field in REQUIRED_FIELDS:
        if field not in sig:
            return False, f"Missing field: {field}"
    if sig["confidence"] < 0 or sig["confidence"] > 1:
        return False, f"Confidence out of range: {sig['confidence']}"
    if sig["direction"] not in ("BULLISH", "BEARISH"):
        return False, f"Invalid direction: {sig['direction']}"
    return True, "OK"

def store_signal(sig):
    """Store signal to local JSON log."""
    os.makedirs(OUTPUT_DIR, exist_ok=True)
    ts = datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")
    path = os.path.join(OUTPUT_DIR, f"signal_{ts}_{sig['signal_id'][:8]}.json")
    with open(path, "w") as f:
        json.dump(sig, f, indent=2)
    return path

def main():
    print(f"[consumer] Polling {PRODUCER_ENDPOINT} every {POLL_INTERVAL}s")
    while True:
        try:
            signals = fetch_signals()
            for sig in (signals if isinstance(signals, list) else [signals]):
                ok, msg = validate_signal(sig)
                if ok:
                    path = store_signal(sig)
                    print(f"[consumer] Stored {sig['signal_id'][:8]} -> {path}")
                else:
                    print(f"[consumer] REJECTED {sig.get('signal_id', '?')}: {msg}")
        except Exception as e:
            print(f"[consumer] ERROR: {e}")
        time.sleep(POLL_INTERVAL)

if __name__ == "__main__":
    main()
